INSERT INTO metro_races_priority (mc_number, tier, voter_count, sleeper_dems, independents, strategy_summary_md) VALUES (17, 'HIGHEST', 22782, 3934, 1930, '**MC 17 · Winkler.** 22,782 voters · 6 DEFEND precincts · 3,934 sleeper Dems · 1,930 Independents. 3,934 sleeper Dems are the margin. This is the seat where one summer of disciplined work flips the council.');
INSERT INTO metro_races_priority (mc_number, tier, voter_count, sleeper_dems, independents, strategy_summary_md) VALUES (7, 'HIGH', NULL, NULL, NULL, '**MC 7 · McCraney.** Power Base district — the job is keeping reliable Dems voting and pulling the chase list to the polls.');
INSERT INTO metro_races_priority (mc_number, tier, voter_count, sleeper_dems, independents, strategy_summary_md) VALUES (21, 'HIGH', 23367, 4081, 1978, '**MC 21 · Ruhe.** 23,367 voters · 18 of 25 ACTIVATE precincts · 4,081 sleeper Dems · 1,978 Independents. Wake the Vote district — biggest pool of sleeper Dems in any single MC. Owned by the November cycle.');
INSERT INTO content_cards (slug, title, section, body_md, display_order, published) VALUES ('how-we-fit', 'How we fit', 'tour_step_1', 'The Democratic National Committee sets national strategy and funds key priorities. The Kentucky Democratic Party runs statewide elections and provides the playbooks, tools, and legal infrastructure counties operate within. The Louisville Democratic Party is the county-level Executive Committee — we''re the ones who actually organize the 629 precincts in Jefferson County, recruit and endorse local candidates, and deliver turnout in the only place where Kentucky Democrats consistently win.', 10, true) ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, section = EXCLUDED.section, body_md = EXCLUDED.body_md, display_order = EXCLUDED.display_order;
INSERT INTO content_cards (slug, title, section, body_md, display_order, published) VALUES ('five-things-ec-owes', 'Five things every Executive Committee owes its county', 'tour_step_1', '1. **Organize precincts.** Keep Precinct Captains filled and active across all 629 precincts.
INSERT INTO content_cards (slug, title, section, body_md, display_order, published) VALUES ('120-club', 'The $120 Club', 'commitments', 'Every Executive Committee member is expected to join the $120 Club: a minimum personal give of $10 a month plus $500 raised for the party each year. This is the operational baseline — the floor, not the ceiling. Signature events and everything else the party does run on every board member pulling their weight here.
INSERT INTO content_cards (slug, title, section, body_md, display_order, published) VALUES ('what-this-portal-is', 'What this portal is and isn''t', 'tour_step_1', '**This portal is:** the internal playbook for LDPEC members. A companion to Google Drive (where working docs live) and louisvilledems.com (where the party talks to voters). Source of truth for roster, monthly work, and what''s live this cycle.
INSERT INTO content_cards (slug, title, section, body_md, display_order, published) VALUES ('volunteer-pipeline', 'Volunteer pipeline', 'tour_step_5', 'The Volunteer Committee is the LDP''s countywide deployment system. Jessica Haggy intakes new volunteers, matches them to a committee or LD that fits, plugs them into the Facebook group and Mobilize, and routes them to the priority districts where countywide volunteer hours move the most votes — Metro Council 17 (Winkler), 21 (Ruhe), and 7 (McCraney). LD Chairs and Vice Chairs are the front door of this pipeline. If you don''t pass a volunteer up, they vanish.
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (1, 2026, '**January — Planning & refresh.** File your Q4 LD report (due this month). Build next year''s LD calendar. Set personal $120 Club raise target. Platform Committee opens for revision.', 'OFF_CYCLE', true);
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (2, 2026, '**February — Primary prep.** Candidates file; Endorsement process activates. Training Committee runs new LD chair + canvass basics. Celebration of Democracy Dinner ticket push opens.', 'PRIMARY_WINDOW', true);
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (3, 2026, '**March — Canvass kickoff + dinner.** Celebration of Democracy Dinner last Saturday of the month — sell tickets, host a table, bring guests. Canvass waves begin in priority MC overlap districts.', 'PRIMARY_WINDOW', true);
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (4, 2026, '**April — Full canvass cadence.** Weekly canvass shifts in priority MC precincts. Volunteer pipeline in full motion. Endorsements finalize before May.', 'PRIMARY_WINDOW', true);
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (5, 2026, '**May — Primary week + GOTV.** Primary is May 19. Final GOTV in contested districts. File your Q1 LD report. Debrief early in the month.', 'PRIMARY_WINDOW', true);
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (6, 2026, '**June — Regroup + committee joins.** Post-primary debrief at LDPEC. Recruit volunteers who showed up in May onto committees. Plan summer engagement.', 'POST_PRIMARY', true);
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (7, 2026, '**July — Registration drives + PC recruiting.** Summer voter registration campaigns. Start recruiting PC candidates for 2028 Precinct Conventions. File Q2 LD report.', 'SUMMER', true);
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (8, 2026, '**August — Women Deliver Democracy.** WDD this month — push tickets, bring guests, host a table. Continue canvass prep for general election ramp.', 'SUMMER', true);
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (9, 2026, '**September — General canvass kickoff.** Full canvass cadence restarts. Hold the Line precincts get weekly attention. Volunteer pipeline refills for November.', 'GENERAL', true);
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (10, 2026, '**October — Peak GOTV prep.** Daily canvass shifts in priority districts. Early voting starts late-month — drive turnout. File Q3 LD report.', 'GENERAL', true);
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (11, 2026, '**November — Election week + Dems at the Downs.** General election November 3. Final GOTV. Dems at the Downs post-election — celebrate, close out the cycle, thank everyone who showed up.', 'ELECTION_WEEK', true);
INSERT INTO month_cards (month, year, content_md, theme_tag, published) VALUES (12, 2026, '**December — Annual wrap.** Annual LD data review with the LDP Chair. Volunteer appreciation outreach. File Q4 LD report. Set goals for next year. Optional: holiday community engagement.', 'POST_GENERAL', true);
